// в”Ђв”Ђв”Ђ GOLD (PAXG) Trading Indicators в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// toolCode nodes must return a plain string вЂ” the LLM reads it as tool output.

async function getData(interval) {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.binance.com/api/v3/klines?symbol=PAXGUSDT&interval=${interval}&limit=100`,
    json: true
  });
}

const sma = (arr, n) => arr.slice(-n).reduce((a, b) => a + b, 0) / n;

function calcRSI(closes, period = 14) {
  let gains = 0, losses = 0;
  for (let i = closes.length - period; i < closes.length - 1; i++) {
    const diff = closes[i + 1] - closes[i];
    if (diff >= 0) gains += diff;
    else losses -= diff;
  }
  const rs = gains / (losses || 1);
  return 100 - (100 / (1 + rs));
}

function calcMomentum(closes, period = 10) {
  return closes[closes.length - 1] - closes[closes.length - period];
}

function calcBB(closes, period = 20) {
  const slice    = closes.slice(-period);
  const mean     = sma(slice, period);
  const variance = slice.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / period;
  const std      = Math.sqrt(variance);
  return { upper: mean + 2 * std, middle: mean, lower: mean - 2 * std };
}

function processTF(ohlcv) {
  const closes   = ohlcv.map(c => parseFloat(c[4]));
  const price    = closes[closes.length - 1];
  const sma20    = sma(closes, 20);
  const sma50    = sma(closes, 50);
  const rsi      = calcRSI(closes);
  const momentum = calcMomentum(closes);
  const bb       = calcBB(closes);

  let signal = 'NEUTRAL';
  if (sma20 > sma50 && rsi < 30) signal = 'BUY';
  else if (sma20 < sma50 && rsi > 70) signal = 'SELL';

  return { price, sma20, sma50, rsi, momentum, bb, signal };
}

const [data1h, data4h, data8h] = await Promise.all([
  getData('1h'),
  getData('4h'),
  getData('8h')
]);

const tf1 = processTF(data1h);
const tf4 = processTF(data4h);
const tf8 = processTF(data8h);

const signals   = [tf1.signal, tf4.signal, tf8.signal];
const buyCount  = signals.filter(s => s === 'BUY').length;
const sellCount = signals.filter(s => s === 'SELL').length;

let final = 'NEUTRAL';
if      (buyCount  >= 2) final = 'STRONG_BUY';
else if (sellCount >= 2) final = 'STRONG_SELL';
else if (buyCount  === 1) final = 'WEAK_BUY';
else if (sellCount === 1) final = 'WEAK_SELL';

// toolCode MUST return a plain string
return `GOLD (PAXG) Technical Analysis Results:
Asset: GOLD (PAXG)
Current Price: $${tf1.price.toFixed(2)}

Indicators (1H timeframe):
- RSI: ${tf1.rsi.toFixed(2)}
- SMA20: $${tf1.sma20.toFixed(2)}
- SMA50: $${tf1.sma50.toFixed(2)}
- Momentum: ${tf1.momentum.toFixed(2)}
- Bollinger Upper: $${tf1.bb.upper.toFixed(2)}
- Bollinger Middle: $${tf1.bb.middle.toFixed(2)}
- Bollinger Lower: $${tf1.bb.lower.toFixed(2)}

Signals:
- 1H: ${tf1.signal}
- 4H: ${tf4.signal}
- 8H: ${tf8.signal}

Final Recommendation: ${final}`;

